// Package directory models the venue directory for the bookit platform.
package directory

import "strings"

// Slug derives the directory slug a venue is addressed by from its name.
func Slug(name string) string {
	return strings.ToLower(strings.TrimSpace(name))
}

// Package api exposes the bookit platform HTTP endpoints.
package api

import (
	"github.com/ai-eng-bootcamps/bookit-platform-fixture/internal/directory"
)

// venuePath reports the directory URL path for a venue. The directory package
// owns the slug rule; the handler only routes the question to it.
func venuePath(name string) string {
	return "/venues/" + directory.Slug(name)
}

tests.content:
package directory

import "testing"

func TestSlugLowercases(t *testing.T) {
	if got := Slug("Atrium"); got != "atrium" {
		t.Fatalf("Slug(%q) = %q, want %q", "Atrium", got, "atrium")
	}
}

func TestSlugTrims(t *testing.T) {
	if got := Slug("  Atrium "); got != "atrium" {
		t.Fatalf("Slug(%q) = %q, want %q", "  Atrium ", got, "atrium")
	}
}

